import{c as t,Q as n,j as a,m as o}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"Plans & Meters","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts/plans-and-meters.md","filePath":"guide/concepts/plans-and-meters.md","lastUpdated":1778862269000}'),i={name:"guide/concepts/plans-and-meters.md"};function s(r,e,l,u,c,d){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="plans-meters" tabindex="-1">Plans &amp; Meters <a class="header-anchor" href="#plans-meters" aria-label="Permalink to &quot;Plans &amp; Meters&quot;">​</a></h1><p>The Console&#39;s billing engine is built on two primitives: <strong>meters</strong> measure usage, and <strong>plans</strong> turn usage into money.</p><h2 id="meters" tabindex="-1">Meters <a class="header-anchor" href="#meters" aria-label="Permalink to &quot;Meters&quot;">​</a></h2><p>A meter is a measurable unit of consumption. Each meter has:</p><ul><li>A <strong>name</strong> (snake_case, used internally — e.g. <code>api_calls</code>).</li><li>A <strong>display name</strong> (what customers see — e.g. &quot;API Calls&quot;).</li><li>A <strong>unit</strong> — <code>count</code>, <code>gb</code>, <code>mb</code>, or <code>kb</code>.</li><li>An <strong>aggregation mode</strong> that decides how raw measurements collapse into a billable number: <ul><li><strong>Snapshot</strong> — the latest value wins. Use for gauges like &quot;active users right now&quot;.</li><li><strong>Delta</strong> — values accumulate over the period. Use for counters like &quot;API calls this month&quot;.</li><li><strong>Distinct</strong> — count of unique IDs over the period. Use for session-like metrics.</li></ul></li></ul><p>Some meters are <strong>built-in</strong> and cannot be deleted; others are <strong>custom</strong> and can be created on the <a href="./../admin/finance/meters">Meters</a> page.</p><h2 id="plans" tabindex="-1">Plans <a class="header-anchor" href="#plans" aria-label="Permalink to &quot;Plans&quot;">​</a></h2><p>A plan binds meters to limits and prices. A plan has:</p><ul><li>A <strong>display name</strong> and a generated key.</li><li>A <strong>billing interval</strong> — monthly, quarterly, annual, or perpetual.</li><li>A <strong>type</strong> — Built-in or Custom. Built-in plans (Starter, Professional, Enterprise) are the standard offering; custom plans are for one-off contracts.</li><li>A list of <strong>meter limits</strong>, each consisting of: <ul><li><strong>Included quantity</strong> — usage up to this is included in the plan price. <code>0</code> with a non-zero overage price means &quot;pay per unit from zero&quot;. The word &quot;Unlimited&quot; means no cap.</li><li><strong>Overage unit price</strong> — what each unit above the included quantity costs. <code>$0</code> means <strong>hard limit</strong> — usage above the cap is blocked, not charged.</li></ul></li></ul><h2 id="plan-versions" tabindex="-1">Plan versions <a class="header-anchor" href="#plan-versions" aria-label="Permalink to &quot;Plan versions&quot;">​</a></h2><p>Plans evolve. Rather than mutating an existing plan and breaking history, the Console uses <strong>versions</strong>:</p><ul><li>The <strong>current version</strong> has no retirement date and applies to new customers.</li><li><strong>Retired versions</strong> are read-only. Existing customers stay pinned to whatever version they were on when retired, until you explicitly upgrade them.</li></ul><p>Create a new version from the plan card on the <a href="./../admin/finance/plans">Plans</a> page. It pre-fills with the current version&#39;s meter limits — edit what should change, then click <strong>Create v[N]</strong>. The previous version is automatically retired.</p><h2 id="how-billing-actually-computes" tabindex="-1">How billing actually computes <a class="header-anchor" href="#how-billing-actually-computes" aria-label="Permalink to &quot;How billing actually computes&quot;">​</a></h2><p>For each customer&#39;s invoice period, the Console:</p><ol><li>Gathers raw usage measurements per tenant per meter.</li><li>Aggregates them according to the meter&#39;s mode (snapshot / delta / distinct).</li><li>Applies the plan&#39;s included quantity and overage price.</li><li>Applies any <strong>non-prod multiplier</strong> to non-production tenants (configured per customer on the Billing Setup tab).</li><li>Applies any <strong>per-tenant override</strong> (also on Billing Setup) — multiplier, meter exclusion, or price override.</li><li>Applies the customer&#39;s <strong>tax rate</strong> and any <strong>credit balance</strong>.</li><li>Issues an invoice.</li></ol><p>You can preview usage at any granularity on the <a href="./../admin/finance/usage">Usage</a> page without issuing anything.</p><h2 id="production-vs-non-production" tabindex="-1">Production vs. non-production <a class="header-anchor" href="#production-vs-non-production" aria-label="Permalink to &quot;Production vs. non-production&quot;">​</a></h2><p>The Console treats production and non-production billing separately. On a customer&#39;s Billing Setup:</p><ul><li><strong>Production environments</strong> are listed explicitly. Tenants in those environments are billed at 100% against the plan.</li><li><strong>Non-production billing</strong> can be: free, a percentage of usage, a fixed monthly amount, or based on usage with per-environment defaults (e.g. DEV at 25%, UAT at 50%).</li><li>Each non-production tenant can have a <strong>manual override</strong> that pins its multiplier and meter overrides independently of the environment default.</li></ul><p>Manually-overridden tenants are not affected by changes to the environment default — they keep their pinned values until you reset them.</p><h2 id="where-it-shows-up" tabindex="-1">Where it shows up <a class="header-anchor" href="#where-it-shows-up" aria-label="Permalink to &quot;Where it shows up&quot;">​</a></h2><ul><li>The customer&#39;s <a href="./../admin/finance/customer-billing">Billing Setup tab</a> — assign plan, set tax, configure non-prod billing, override per tenant.</li><li>The customer&#39;s <a href="./../admin/finance/invoices">Invoices</a>, <a href="./../admin/finance/payments">Payments</a>, and credit tables.</li><li>The <a href="./../admin/finance/customer-finance">Customer Finance</a> dashboard — outstanding amounts, overage flags, credit exposure across all customers.</li><li>The <a href="./../admin/finance/usage">Usage</a> page — query aggregated consumption.</li><li>For customers themselves, <a href="./../portal/billing">Portal → Billing</a> — usage with quota bars, invoices, payments, and credit history.</li></ul>',23)])])}const h=t(i,[["render",s]]);export{g as __pageData,h as default};
